mapper.insert:
INSERT INTO reports (
    reporter_id, target_type, target_id, reason_type, reason_detail, status
) VALUES (
    #{reporterId}, #{targetType}, #{targetId}, #{reasonType}, #{reasonDetail}, #{status}
)

mapper.select:
SELECT COUNT(1)
FROM reports
WHERE reporter_id = #{reporterId}
  AND target_type = #{targetType}
  AND target_id = #{targetId}
  AND status IN ('PENDING', 'PROCESSING')

SELECT COUNT(1)
FROM reports
WHERE 1 = 1

    AND target_type = #{targetType}


    AND status = #{status}

SELECT

FROM reports r
INNER JOIN users ru ON ru.id = r.reporter_id
LEFT JOIN users hu ON hu.id = r.handled_by
WHERE 1 = 1

    AND r.target_type = #{targetType}


    AND r.status = #{status}

ORDER BY r.created_at DESC, r.id DESC
LIMIT #{pageSize} OFFSET #{offset}
